    const newGrid = grid.map(row => [...row]);

    // Iterate over each row in the submatrix
    for (let i = 0; i < k; i++) {
        const originalRow = x + i;
        const flippedRow = x + k - 1 - i;

        // Only swap if the original row is before the flipped row to avoid double swapping
        if (originalRow < flippedRow) {
            // Swap the relevant parts of the rows
            for (let j = y; j < y + k; j++) {
                const temp = newGrid[originalRow][j];
                newGrid[originalRow][j] = newGrid[flippedRow][j];
                newGrid[flippedRow][j] = temp;
            }
        }
    }

    return newGrid;
}
